import{_ as e,o as t,c as r,a2 as l}from"./chunks/framework.VxKNwi4m.js";const g=JSON.parse('{"title":"설정","description":"","frontmatter":{},"headers":[],"relativePath":"work-manage/settings.md","filePath":"work-manage/settings.md","lastUpdated":1784134213000}'),o={name:"work-manage/settings.md"};function i(n,a,s,h,d,u){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="설정" tabindex="-1">설정 <a class="header-anchor" href="#설정" aria-label="Permalink to &quot;설정&quot;">​</a></h1><p>프로젝트의 전반적인 환경을 구성하고 관리하는 <strong>설정</strong> 페이지에 대한 사용자 가이드입니다.</p><h2 id="_1-화면-개요" tabindex="-1">1. 화면 개요 <a class="header-anchor" href="#_1-화면-개요" aria-label="Permalink to &quot;1. 화면 개요&quot;">​</a></h2><p>설정 화면은 프로젝트 관리자 및 권한이 있는 구성원이 프로젝트의 기본 정보, 참여 인원, 업무 프로세스 등을 정의하는 공간입니다. 탭 메뉴 방식을 통해 다양한 설정 항목을 체계적으로 관리할 수 있습니다.</p><h2 id="_2-주요-설정-항목-안내" tabindex="-1">2. 주요 설정 항목 안내 <a class="header-anchor" href="#_2-주요-설정-항목-안내" aria-label="Permalink to &quot;2. 주요 설정 항목 안내&quot;">​</a></h2><h3 id="🏗️-프로젝트-기본-정보" tabindex="-1">🏗️ 프로젝트 (기본 정보) <a class="header-anchor" href="#🏗️-프로젝트-기본-정보" aria-label="Permalink to &quot;🏗️ 프로젝트 (기본 정보)&quot;">​</a></h3><ul><li><strong>정보 수정</strong>: 프로젝트 이름, 설명, 식별자(Slug) 등 기본 정보를 변경합니다.</li><li><strong>모듈 활성화</strong>: 업무(이슈), 캘린더, 게시판, 문서 등 해당 프로젝트에서 사용할 기능을 선택하여 활성화하거나 비활성화할 수 있습니다.</li></ul><h3 id="👥-구성원-관리" tabindex="-1">👥 구성원 관리 <a class="header-anchor" href="#👥-구성원-관리" aria-label="Permalink to &quot;👥 구성원 관리&quot;">​</a></h3><ul><li><strong>팀원 구성</strong>: 프로젝트에 참여할 사용자를 추가하거나 제외합니다.</li><li><strong>역할 및 권한</strong>: 각 구성원에게 &#39;관리자&#39;, &#39;개발자&#39;, &#39;보고자&#39; 등의 역할을 부여하여 기능별 접근 권한을 세밀하게 제어합니다.</li></ul><h3 id="🛤️-업무추적-및-범주" tabindex="-1">🛤️ 업무추적 및 범주 <a class="header-anchor" href="#🛤️-업무추적-및-범주" aria-label="Permalink to &quot;🛤️ 업무추적 및 범주&quot;">​</a></h3><ul><li><strong>업무추적</strong>: 해당 프로젝트에서 사용할 이슈 트래커(예: 결함, 지원, 기능 등)를 선택합니다.</li><li><strong>업무범주</strong>: 업무를 논리적으로 그룹화할 수 있는 범주(예: UI, 백엔드, 기획 등)를 생성하고 담당자를 지정하여 업무 배분을 자동화할 수 있습니다.</li></ul><h3 id="📅-단계-마일스톤-버전" tabindex="-1">📅 단계 (마일스톤/버전) <a class="header-anchor" href="#📅-단계-마일스톤-버전" aria-label="Permalink to &quot;📅 단계 (마일스톤/버전)&quot;">​</a></h3><ul><li><strong>일정 관리</strong>: 프로젝트의 주요 마일스톤이나 출시 버전을 관리합니다.</li><li><strong>진척도 확인</strong>: 각 단계별로 할당된 업무의 진행률을 추적하여 전체 로드맵을 관리하는 기준이 됩니다.</li></ul><h3 id="📋-게시판-설정" tabindex="-1">📋 게시판 설정 <a class="header-anchor" href="#📋-게시판-설정" aria-label="Permalink to &quot;📋 게시판 설정&quot;">​</a></h3><ul><li><strong>소통 공간 정의</strong>: 프로젝트 내에서 사용할 게시판의 이름과 설명을 설정합니다.</li><li><strong>카테고리 구성</strong>: 게시판 내에서 글을 분류할 카테고리를 추가하여 정보를 정돈합니다.</li></ul><h2 id="_3-주요-특징-및-이용-팁" tabindex="-1">3. 주요 특징 및 이용 팁 <a class="header-anchor" href="#_3-주요-특징-및-이용-팁" aria-label="Permalink to &quot;3. 주요 특징 및 이용 팁&quot;">​</a></h2><h3 id="🔐-권한에-따른-메뉴-노출" tabindex="-1">🔐 권한에 따른 메뉴 노출 <a class="header-anchor" href="#🔐-권한에-따른-메뉴-노출" aria-label="Permalink to &quot;🔐 권한에 따른 메뉴 노출&quot;">​</a></h3><ul><li>설정 메뉴는 사용자의 권한(<code>workManager</code> 또는 프로젝트별 부여 권한)에 따라 노출되는 항목이 달라집니다. 중요 설정(구성원 변경, 프로젝트 삭제 등)은 관리자 권한이 필요합니다.</li></ul><h3 id="🍪-마지막-탭-기억-기능" tabindex="-1">🍪 마지막 탭 기억 기능 <a class="header-anchor" href="#🍪-마지막-탭-기억-기능" aria-label="Permalink to &quot;🍪 마지막 탭 기억 기능&quot;">​</a></h3><ul><li>사용자가 마지막으로 머물렀던 설정 탭은 브라우저 쿠키를 통해 저장됩니다. 다음에 설정 화면에 다시 진입할 때 이전에 작업하던 탭이 자동으로 활성화되어 편리합니다.</li></ul><h3 id="💡-유연한-모듈-구성" tabindex="-1">💡 유연한 모듈 구성 <a class="header-anchor" href="#💡-유연한-모듈-구성" aria-label="Permalink to &quot;💡 유연한 모듈 구성&quot;">​</a></h3><ul><li>프로젝트의 성격에 따라 필요한 모듈만 켜고 끌 수 있습니다. 예를 들어, 단순 공지용 프로젝트라면 &#39;업무&#39; 모듈을 끄고 &#39;게시판&#39;만 활성화하여 가볍게 운영할 수 있습니다.</li></ul>',22)])])}const _=e(o,[["render",i]]);export{g as __pageData,_ as default};
